import React, { useState } from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import UserPage from './pages/UserPage';
import VerifierPage from './pages/VerifierPage';
import Node2Page from './pages/Node2Page';
import CheckStatus from './pages/CheckStatus';

const App: React.FC = () => {
  const [walletAddress, setWalletAddress] = useState<string>('');

  return (
    <BrowserRouter>
      <div style={{ 
        backgroundColor: '#f8f9fa', 
        minHeight: '100vh', 
        fontFamily: 'Arial, sans-serif' 
      }}>
        <Navbar 
          walletAddress={walletAddress} 
          onConnected={(addr) => setWalletAddress(addr)} 
        />

        <div style={{ padding: '40px 20px' }}>
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/register" element={<UserPage walletAddress={walletAddress} />} />
            <Route path="/verifier" element={<VerifierPage walletAddress={walletAddress} />} />
            <Route path="/node2" element={<Node2Page walletAddress={walletAddress} />} />
            <Route path="/status" element={<CheckStatus />} />
          </Routes>
        </div>

        {/* Global Spinner Animation */}
        <style>
          {`
            @keyframes spin {
              0% { transform: rotate(0deg); }
              100% { transform: rotate(360deg); }
            }
          `}
        </style>
      </div>
    </BrowserRouter>
  );
};

export default App;
